def range_summary(nums):
    runs = []
    i, last = 0, None
    for n in sorted(set(nums)):
        if last is not None and n == last + 1:
            runs[-1][1] = n
        else:
            runs.append([last, n])
            i += 1
    if len(runs) > 1:
        return ', '.join('-'.join(str(x) for x in run) for run in runs[:-1]) + f',{runs[-1][0]}-{runs[-1][1]}'
    elif runs:
        return str(runs[0][0])
    else:
        return ''
